  public static class CustomTypeAdapterFactory implements TypeAdapterFactory {
    @SuppressWarnings("unchecked")
    @Override
    public <T> TypeAdapter<T> create(Gson gson, TypeToken<T> type) {
       if (!EcfResponse.class.isAssignableFrom(type.getRawType())) {
         return null; // this class only serializes 'EcfResponse' and its subtypes
       }
       final TypeAdapter<JsonElement> elementAdapter = gson.getAdapter(JsonElement.class);
       final TypeAdapter<EcfResponse> thisAdapter
                        = gson.getDelegateAdapter(this, TypeToken.get(EcfResponse.class));

       return (TypeAdapter<T>) new TypeAdapter<EcfResponse>() {
           @Override
           public void write(JsonWriter out, EcfResponse value) throws IOException {
             JsonObject obj = thisAdapter.toJsonTree(value).getAsJsonObject();
             elementAdapter.write(out, obj);
           }

           @Override
           public EcfResponse read(JsonReader in) throws IOException {
             JsonElement jsonElement = elementAdapter.read(in);
             validateJsonElement(jsonElement);
             return thisAdapter.fromJsonTree(jsonElement);
           }

       }.nullSafe();
    }
  }

